class Solution:
    def validTicTacToe(self, board):
        flat = ''.join(board)
        # Brute force: enumerate all reachable boards by simulating every game
        # of alternating X/O moves and stopping when a line completes or full.
        target = tuple(flat)
        reachable = set()
        lines = [(0,1,2),(3,4,5),(6,7,8),(0,3,6),(1,4,7),(2,5,8),(0,4,8),(2,4,6)]
        def won(state, who):
            return any(state[a]==who and state[b]==who and state[c]==who for a,b,c in lines)
        def dfs(state, turn):
            if state in reachable:
                return
            reachable.add(state)
            if won(state, 'X') or won(state, 'O') or all(c != ' ' for c in state):
                return
            mark = 'X' if turn % 2 == 0 else 'O'
            for i in range(9):
                if state[i] == ' ':
                    nxt = state[:i] + (mark,) + state[i+1:]
                    dfs(nxt, turn + 1)
        dfs(tuple(' '*9), 0)
        return target in reachable

