class Solution:
    def validTicTacToe(self, board):
        flat = ''.join(board)
        x = flat.count('X')
        o = flat.count('O')
        lines = [(0,1,2),(3,4,5),(6,7,8),(0,3,6),(1,4,7),(2,5,8),(0,4,8),(2,4,6)]
        def wins(who):
            return any(flat[a]==who and flat[b]==who and flat[c]==who for a,b,c in lines)
        if o > x or x > o + 1:
            return False
        if wins('X') and x != o + 1:
            return False
        if wins('O') and x != o:
            return False
        return True

